"""
mkt-original — Genesis chapters 43-45
Run: python3 scripts/zc-original-genesis-43-45.py

Key linguistic coverage:
- Ch 43: kāḇēḏ (heavy) famine (v1); hēʿēḏ emphatic solemn-warning (v3);
  ʿāraḇ Judah's surety-pledge echoing ch38 eravon (v9); El Shaddai name (v14);
  šāḵal bereavement verb (v14); ṭāḇaḥ/slaughter root (v16); steward's
  covenant-language (v23); bow-fulfillment of Joseph's dreams (v26);
  ḥānan grace-blessing for Benjamin (v29); raḥămîm/kāmar womb-compassion (v30);
  separate tables/tôʿēḇāh abomination (v32); five portions (v34)
- Ch 44: gaḇîaʿ silver cup (v2); nāḥēš divination (v5); ḥālîlāh oath-formula (v7);
  qāraʿ tear-garments mourning (v13); Judah's triple rhetorical question (v16);
  Elohim "found" guilt (v16); Judah's speech structure (vv18-34); nepeš qāšar
  life-bound-together (v30); taḥat substitution echoing Gen 22:13 (v33)
- Ch 45: ʾāpaq Hithpael self-restraint broken (v1); three-word revelation (v3);
  wĕʿattāh ʾal-tēʿāṣĕḇû release from guilt (v5); lĕmiḥyāh life-preservation (v5,7);
  šĕlāḥanî ʾĕlōhîm God-sent formula (vv5,7,8); theological pivot "not you but God" (v8);
  ʾāḇ lĕparʿōh triple title (v8); ṣawwāʾr neck-embrace (v14); ʾal-tirgeʾzû
  don't-quarrel parting word (v24); rûaḥ wattĕḥî reviving spirit (v27)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

GENESIS_ORIGINAL = {
  "43": {
    "1": """<p><strong>wĕhārāʿāḇ kāḇēḏ bāʾāreṣ</strong> — "The famine was heavy (<em>kāḇēḏ</em>) in the land." <em>Kāḇēḏ</em> (H3515, heavy/severe/weighty) — the same root as <em>kāḇôḏ</em> (glory, the weightiness of God's presence). In narrative usage <em>kāḇēḏ</em> describes the severity of plagues, famines, and hardships: the Egyptian slavery is "heavy" in Exod 1:14; Pharaoh's heart is "heavy" (Hiphil, hardened) in Exod 7:14. The famine's <em>kāḇēḏ</em> is what drives every subsequent action in chs 43–45.</p>""",
    "2": """<p><strong>wayhî kaʾăšer killû lĕʾĕkōl ʾet-hašŝeḇer</strong> — "When they had finished eating all the grain they had brought." <em>Killû</em> (Piel of <em>kālāh</em>, H3615, to finish/consume/complete) — the exhaustion of provisions creates narrative compulsion; the brothers must return. The same <em>kālāh</em> root is used for the completion of creation (2:1-2) and for the covenant formulas "as of this day" — the verb of finality that drives action.</p>""",
    "3": """<p><strong>hēʿēḏ hēʿîḏ ḇānû hāʾîš lēʾmōr lōʾ-tirʾû pānay</strong> — "The man solemnly warned us, 'You shall not see my face.'" The infinitive absolute + finite verb construction <em>hēʿēḏ hēʿîḏ</em> (Hiphil infinitive absolute + Hiphil perfect of <em>ʿûḏ</em>, H5749, to testify/warn) — "he warned with a warning" — the emphatic doubling that signals an irrevocable, solemn declaration. The same construction underlies "dying you will die" (2:17: <em>môṯ tāmûṯ</em>) and "being cut off he will be cut off" for covenant violations. Joseph's injunction is given the force of oath-like finality.</p>""",
    "4": """<p><strong>ʾim-yešĕḵā mĕšalēaḥ ʾet-ʾāḥînû ʾittānû nērĕḏāh wĕnišbĕrāh-llĕḵā ʾōḵel</strong> — "If you will send our brother with us, we will go down and buy food for you." <em>Mĕšalēaḥ</em> (Piel participle of <em>šālaḥ</em>, H7971, to send/release) — the sending-verb that has governed the narrative: Jacob sent Joseph (37:13-14), God will declare he sent Joseph (45:5,8). Here Judah uses the participle condition: "if you are sending." The entire chapter turns on this sending-authorization.</p>""",
    "5": """<p><strong>wĕʾim-ʾênĕḵā mĕšalēaḥ lōʾ nērēḏ</strong> — "But if you will not send him, we will not go down." The parallel negative condition is blunt — there is no diplomatic softening. The brothers have accepted Benjamin's necessity as non-negotiable. The statement reverses the earlier dynamic of ch 42 where Jacob had authority; now Judah speaks with conditional authority over the family's course.</p>""",
    "6": """<p><strong>wayyōʾmer yiśrāʾēl lāmmāh harēʾōtem lî lĕhaggîḏ lāʾîš ha-ʿôḏ lāḵem ʾāḥ</strong> — "Israel said, 'Why did you bring this trouble on me by telling the man you had another brother?'" <em>Harēʾōtem lî</em> (you did evil to me — Hiphil of <em>rāʿaʿ</em>, H7489, to do evil/harm) — Jacob uses the evil-verb (<em>ra</em>) for his sons' disclosure, ironically: the brothers' honest answer to Joseph's interrogation (42:13) is what Jacob calls "evil." The narrative irony is that Jacob's protective concealment of Benjamin has been the source of the crisis.</p>""",
    "7": """<p><strong>wayyōʾmĕrû šāʾôl šāʾal hāʾîš lānû wĕlĕmôladtēnû</strong> — "They replied, 'The man questioned us closely (<em>šāʾôl šāʾal</em>) about ourselves and our family.'" The infinitive absolute + perfect again — <em>šāʾôl šāʾal</em> (H7592, to ask) — "he asked with asking/he questioned intensely." The brothers defend their disclosure: they were interrogated, not volunteering. The emphasis distinguishes innocent compliance from treachery.</p>""",
    "8": """<p><strong>šĕlaḥ hannáʿar ʾittî wĕnāqûmāh wĕnēlēḵāh wĕniḥyeh wĕlōʾ nāmût</strong> — "Send the boy with me and we will arise and go, that we may live and not die." Judah's plea is structured around the life/death polarity: <em>wĕniḥyeh</em> (we shall live, from <em>ḥāyāh</em>, H2421) vs. <em>wĕlōʾ nāmût</em> (we shall not die, from <em>mût</em>, H4191). This same polarity governs the entire Joseph cycle: the brothers' survival is the stated divine purpose Joseph will articulate in 45:5 (<em>lĕmiḥyāh</em>, to keep alive). Life is the narrative's telos.</p>""",
    "9": """<p><strong>ʾānōḵî eʿĕrĕbennû miyyāḏî tĕḇaqšennû</strong> — "I myself will be surety for him; from my hand you shall require him." <em>ʾĒraḇ</em> (H6148, to become surety/pledge, to give security for another) — the same root as <em>ʿēreḇôn</em> (pledge, 38:17-20) that Judah gave Tamar. There Judah treated a pledge as disposable; here he pledges himself with his own life. Judah's transformation from the man who traded Joseph for profit (37:26-27) and failed his Tamar-obligation (38:11) to the man who voluntarily becomes surety for Benjamin is the moral arc the narrative has been building. The Hiphil <em>tĕḇaqšennû</em> (you shall require him) — the demanding-back formula of covenant surety.</p>""",
    "10": """<p><strong>kî lûlēʾ hiṯmahmāhnû kî-ʿattāh šaḇnû zeh paʿămāyim</strong> — "For if we had not delayed, by now we could have gone and returned twice." <em>Hiṯmahmāhnû</em> (Hithpael of <em>māhah</em>, H4102, to linger/delay/hesitate) — the reflexive hesitation-verb; Lot is urged not to linger (<em>hiṯmahmēah</em>) in Sodom (19:16). Judah's acknowledgment of the family's delay frames the urgency: each day of delay costs lives. The pragmatic argument follows the covenantal one (v9).</p>""",
    "11": """<p><strong>qĕḥû miznĕḇat hāʾāreṣ biḵlêḵem ûhôrîḏû lāʾîš minhāh</strong> — "Take some of the best products of the land in your bags, and carry down to the man a gift (<em>minhāh</em>)." <em>Minhāh</em> (H4503, gift/tribute/offering — also the technical term for the grain offering in Leviticus) — the same word Jacob used when sending gifts to appease Esau (32:14,19; 33:10). The gift-list that follows — balm, honey, spices, myrrh, pistachios, almonds — is virtually identical to the cargo of the Ishmaelite traders who carried Joseph to Egypt (37:25). Jacob sends the produce of Canaan to Egypt by the same goods-channel that his other son traveled. The narrative parallelism is pointed.</p>""",
    "12": """<p><strong>wĕḵesef mišneh qĕḥû ḇĕyedḵem</strong> — "Take double the silver in your hand." <em>Mišneh</em> (H4932, double/second) — the double-silver instruction accounts for the possibility that the first return of silver was accidental; doubling it removes any grounds for accusation. The root <em>šānāh</em> (to repeat/double) governs the Joseph narrative structurally: Joseph's double dreams (37:5-10); Pharaoh's double dreams (41:1-8); the double silver returned in sacks (42:25-35) — divine doubling as the signature of certainty (41:32).</p>""",
    "13": """<p><strong>wĕʾet-ʾăḥîḵem qāḥû wĕqûmû šûḇû ʾel-hāʾîš</strong> — "Take your brother also, and arise, go back to the man." Jacob's three imperatives (<em>qāḥû… qûmû… šûḇû</em> — take, arise, return) signal a final authorization after all his resistance. The word <em>šûḇû</em> (return, H7725) — the return-journey verb that bookends the Egypt episodes. Jacob has yielded to necessity; his next speech (v14) reframes the surrender as faith.</p>""",
    "14": """<p><strong>wĕʾēl šadday yittēn lāḵem raḥămîm lĕpĕnê hāʾîš wĕšillaḥ lāḵem ʾet-ʾăḥîḵem ʾaḥēr wĕʾet-binyāmîn</strong> — "May El Shaddai give you mercy before the man, and may he send back your other brother and Benjamin." <em>ʾĒl Šadday</em> (H410 + H7706, God Almighty — the patriarchal covenant name) — first revealed to Abraham at 17:1 ("I am El Shaddai; walk before me"), reiterated at Isaac's blessing of Jacob (28:3), at Jacob's Bethel theophany (35:11), and Jacob's blessing of Joseph (48:3). El Shaddai is the name associated with the covenant promise when it appears impossible — God who can do what seems beyond nature. Jacob invokes it here precisely because the situation is desperate: two sons are at risk, his household may be destroyed, and the famine continues. <em>Raḥămîm</em> (H7356, deep mercies/compassion — from <em>reḥem</em>, womb) — Jacob asks for womb-love from the Egyptian official; he is praying that God will make the official respond to his sons with maternal-covenant care.</p>""",
    "14": """<p><strong>wĕʾănî kaʾăšer šāḵōltî šāḵāltî</strong> — "And as for me, if I am bereaved, I am bereaved." <em>Šāḵōltî šāḵāltî</em> (Qal infinitive absolute + perfect of <em>šāḵal</em>, H7921, to be bereaved of children, to lose offspring) — the infinitive absolute used for resigned finality: "if I am going to lose children, I will lose them." The same verb describes Rachel "weeping for her children" in Jer 31:15 (the <em>mĕšakkēlāh</em>, the one bereaved of children, cited in Matt 2:18). Jacob's acceptance formula is not passive fatalism but a release of control: he cannot prevent loss, so he commends his sons to El Shaddai and lets go.</p>""",
    "15": """<p><strong>wayyiqqĕḥû hāʾănāšîm ʾet-hamminhāh hazzōʾt ûmišneh-kesef lāqĕḥû bĕyāḏām wĕʾet-binyāmîn</strong> — "The men took this gift, and double silver in their hand, and Benjamin." The three-item preparation — gift, double silver, Benjamin — executes Jacob's triple command (v13: take, arise, return). The narrative compression ("they took and went down") moves swiftly to Egypt; the lingering has been in Canaan; the action unfolds in Egypt.</p>""",
    "16": """<p><strong>wayyarʾ yôsēp ʾittām ʾet-binyāmîn wayyōʾmer laʾăšer ʿal-bêtô hāḇēʾ ʾet-hāʾănāšîm habbāytāh ûṭĕḇōaḥ ṭeḇaḥ</strong> — "Joseph saw Benjamin with them and said to his household steward, 'Bring the men into the house, and slaughter an animal and prepare it.'" <em>Ṭĕḇōaḥ ṭeḇaḥ</em> (slaughter a slaughter — Qal infinitive absolute + imperative of <em>ṭāḇaḥ</em>, H2873) — the emphatic slaughtering command; <em>ṭāḇaḥ</em> is the root of <em>ṭabbāḥ</em> (slaughterer/bodyguard), the title of Potiphar and his office (39:1). The royal slaughter for a feast signals immediate, lavish hospitality — the highest honor code of the ancient world. Joseph's first act on seeing Benjamin is to prepare a banquet.</p>""",
    "17": """<p><strong>wayyaʿaś hāʾîš kaʾăšer ʾāmar yôsēp wayyāḇēʾ hāʾîš ʾet-hāʾănāšîm bêtāh yôsēp</strong> — "The man did as Joseph said, and brought the men into Joseph's house." The steward executes the command without delay — the household operates under Joseph's complete authority. The men are brought "into Joseph's house" — the same household that Potiphar once entrusted entirely to Joseph (39:4-5), now restored as Joseph's own domain.</p>""",
    "18": """<p><strong>wayyîrĕʾû hāʾănāšîm kî hûḇĕʾû bêt yôsēp wayyōʾmĕrû ʿal-dĕḇar hakkesef</strong> — "The men were afraid because they had been brought into Joseph's house, and they said, 'It is because of the silver.'" <em>Wayyîrĕʾû</em> (they feared, H3372) — their fear is reasonable: in their cultural framework, being brought to an official's private house meant accusation, not hospitality. The returned silver (42:25-35) has made them guilty-feeling, and the private invitation confirms their anxiety. Their interior speech anticipates slavery and death — the maximum penalty they fear.</p>""",
    "19": """<p><strong>wayyiggĕšû ʾel-hāʾîš ʾăšer ʿal-bêt yôsēp wayyĕḏabbĕrû ʾēlāyw petaḥ habbāyit</strong> — "They came near to the man who was over Joseph's household and spoke with him at the entrance of the house." <em>Wayyiggĕšû</em> (they drew near, Niphal of <em>nāgaš</em>, H5066) — the approach for communication or supplication; Judah will use the same approach before Joseph in 44:18 for his climactic plea. The entrance (<em>petaḥ</em>, H6607) is the threshold space where status negotiations occur — Lot met the angels at the entrance of Sodom (19:1).</p>""",
    "20": """<p><strong>wayyōʾmĕrû bî ʾăḏōnî yārōḏ yāraḏnû ḇattĕḥillāh lišbor-ʾōḵel</strong> — "They said, 'Please, my lord, we came down the first time to buy food.'" <em>Bî ʾăḏōnî</em> (please, my lord — literally "by/through me, my lord") — the formal petition particle; the same phrase used in Abraham's bargaining with God (18:27,30,32). The brothers are positioning themselves as supplicants before authority, echoing covenant-petition language.</p>""",
    "21": """<p><strong>wayhî kî-bānû ʾel-hammālôn wannipĕtĕḥāh ʾet-ʾamtĕḥōtênû wĕhinnēh kesef-ʾîš bĕpî ʾamtaḥtô</strong> — "When we came to the lodging place we opened our sacks, and behold, each man's silver was in the mouth of his sack, full weight." The <em>wĕhinnēh</em> (behold!) marks the brothers' subjective shock — the silver was an astonishing, unexplainable discovery. Their explanation of it to the steward establishes their innocence: they are not hiding it but reporting it. The returned silver is framed as supernatural, not theft.</p>""",
    "22": """<p><strong>wĕḵesef ʾaḥēr hôraḏnû bĕyāḏênû lišbor-ʾōḵel lōʾ yāḏaʿnû mî-śām kaspēnû bĕʾamtĕḥōtênû</strong> — "And we have brought additional silver with us to buy food; we don't know who put our silver in our sacks." The double silver returns as evidence of good faith: they have the original silver plus more. Their disclaimer of knowledge — "we do not know who put it" — is honest but also ironic: the reader knows Joseph ordered it (42:25). The gap between narrator-knowledge and character-knowledge creates the dramatic tension.</p>""",
    "23": """<p><strong>wayyōʾmer šālôm lāḵem ʾal-tîrāʾû ʾĕlōhêḵem wēʾlōhê ʾăḇîḵem nātan lāḵem maṭmôn bĕʾamtĕḥōtêḵem</strong> — "He said, 'Peace to you, do not be afraid. Your God and the God of your father has given you treasure in your sacks.'" The steward's words are theologically remarkable: an Egyptian household official attributes the returned silver to "your God and the God of your father" — using the exact covenant-identification formula. Whether he has been briefed by Joseph (likely) or speaks from genuine theological awareness, the words are the narrator's device: God's providence is being confessed through an Egyptian mouth, before the revelation of 45:5-8. <em>Šālôm</em> (H7965, peace/wholeness/well-being) — the covenant-peace word; it will resonate when the brothers eventually return to their father carrying news of Joseph's shalom (45:9).</p>""",
    "24": """<p><strong>wayyāḇēʾ hāʾîš ʾet-hāʾănāšîm bêtāh yôsēp wayyittēn-māyim wayyirḥăṣû raglêhem</strong> — "The man brought the men into Joseph's house and gave them water, and they washed their feet." Foot-washing for guests was the standard hospitality gesture of the ancient world (cf. Abraham's washing the feet of the three visitors in 18:4; Lot in 19:2). The sequence — water, foot-washing, fodder for the donkeys, table prepared — follows the full ANE hospitality protocol. The brothers are being received as honored guests by the very man who they fear intends to enslave them.</p>""",
    "25": """<p><strong>wayyāḵînû ʾet-hamminhāh ʿaḏ-ḇôʾ yôsēp ḇaṣṣohŏrāyim kî šāmĕʿû kî-šām yōʾḵĕlû leḥem</strong> — "They prepared the gift for Joseph's arrival at noon, for they heard that they were to eat a meal there." <em>Ṣohŏrāyim</em> (H6672, noon/midday) — the noon hour is a time of heat, rest, and formal meals in the ancient Near East. The brothers' preparation of the gift while waiting reflects ANE gift-protocol: the tribute is prepared and presented at the moment of meeting, not left casually. The verb <em>hēkîn</em> (prepared, Hiphil of <em>kûn</em>, H3559, to establish/prepare/make ready) — the same word for divine preparation throughout the Psalms (Ps 23:5: "you prepare a table before me").</p>""",
    "26": """<p><strong>wayyāḇōʾ yôsēp habbāytāh wayyāḇîʾû lô ʾet-hamminhāh ʾăšer bĕyāḏām habbāytāh wayyiššĕtaḥăwû lô ʾarṣāh</strong> — "Joseph came into the house, and they brought the gift into the house to him and bowed down (<em>wayyiššĕtaḥăwû</em>) before him to the ground." <em>Hištaḥăwāh</em> (Hithpael of <em>šāḥāh</em>, H7812, to bow down/prostrate oneself) — the full prostration; the fulfillment of Joseph's first dream: "your sheaves bowed down to my sheaf" (37:7, <em>tishtaḥăwaynāh</em>). The brothers enact Joseph's dream without knowing it. This is the third occurrence: first in 42:6 (ten brothers bow), again in 42:9 (Joseph remembered the dreams), now with Benjamin present completing the eleven.</p>""",
    "27": """<p><strong>wayyišʾal lāhem lĕšālôm wayyōʾmer hăšālôm ʾăḇîḵem hazāqēn ʾăšer ʾămartem ha-ʿôḏĕnnû ḥay</strong> — "He asked about their welfare and said, 'Is your father well, the old man you spoke of? Is he still alive?'" Joseph's first question is about his father; <em>šālôm</em> (peace/welfare) is asked twice — for the brothers collectively, then specifically for the father. The father-question is the emotional center: Joseph has not seen Jacob for over twenty years. The phrase <em>ha-ʿôḏĕnnû ḥay</em> (is he still alive) — the same question Joseph will ask with tears after the revelation (45:3).</p>""",
    "28": """<p><strong>wayyōʾmĕrû šālôm lĕʿaḇdĕḵā lĕʾāḇînû ʿôḏennû ḥay wayyiqĕḏû wayyiššĕtaḥăwû</strong> — "They said, 'Your servant our father is well; he is still alive.' And they bowed and prostrated themselves." A second prostration — the brothers bow again. Their answer uses the covenant-speech formula: "your servant our father" — positioning Jacob as a subordinate of Joseph even as they report his health. The double-bow (v26 and v28) underscores the dream-fulfillment. The formula <em>ʿôḏennû ḥay</em> (he is still alive) — the life-affirmation that Joseph desperately needed to hear.</p>""",
    "29": """<p><strong>wayyiśśāʾ ʿênāyw wayyarʾ ʾet-binyāmîn ʾāḥîw ben-ʾimmô wayyōʾmer ha-zeh ʾăḥîḵem haqqāṭān… ʾĕlōhîm yāḥunnĕḵā ḇĕnî</strong> — "He looked up and saw his brother Benjamin, his mother's son… and said, 'God be gracious to you, my son.'" <em>Ben-ʾimmô</em> (son of his mother) — Benjamin alone shares Joseph's mother Rachel; the identification is the deepest possible kinship designation. The blessing <em>ʾĕlōhîm yāḥunnĕḵā</em> (God be gracious to you) — Qal imperfect jussive of <em>ḥānan</em> (H2603, to be gracious, show favor, act with covenant-grace) — Joseph blesses his full-brother with the same grace-vocabulary that defines God's covenant relationship. The word <em>ḇĕnî</em> (my son) from a man only slightly older than Benjamin is an emotional overflow, not a literal claim.</p>""",
    "30": """<p><strong>wayyĕmahēr yôsēp kî-niḵmĕrû raḥămāyw ʾel-ʾāḥîw wayyĕḇaqqēš liḇkôṯ</strong> — "Joseph hurried out, for his compassion grew warm (<em>niḵmĕrû raḥămāyw</em>) for his brother, and he sought to weep." Two remarkable verbs: <em>kāmar</em> (H3648, Niphal: to grow warm/be deeply stirred, to be kindled with emotion — used for the woman whose maternal compassion "yearned" for her child in 1 Kgs 3:26: <em>wayyikhmĕrû raḥămeyhā</em>) + <em>raḥămîm</em> (H7356, deep mercies/compassion — the plural of <em>reḥem</em>, womb, the seat of maternal-covenantal love). Together these two words describe the most intense, physiologically-located emotional response in biblical Hebrew: Joseph's body responds to Benjamin as a womb responds to its child. The narrator is telling us that Joseph's love for his brother is of the same quality as the divine <em>raḥămîm</em> — God's womb-love for Israel (Isa 49:15).</p>""",
    "31": """<p><strong>wayyirḥaṣ pānāyw wayyēṣēʾ wayyiṯʾappaq wayyōʾmer śîmû leḥem</strong> — "He washed his face and came out, and controlling himself (<em>wayyiṯʾappaq</em>) said, 'Serve the meal.'" <em>Wayyiṯʾappaq</em> (Hithpael of <em>ʾāpaq</em>, H662, to restrain/control oneself) — the same verb used for Joseph's self-restraint breaking in 45:1 (<em>lōʾ-yāḵōl lĕhiṯʾappēq</em>, could no longer restrain himself). Here in 43:31 he succeeds in containing himself; in 45:1 the dam breaks. The Hithpael reflexive — he controls himself against himself — captures the enormous internal effort of suppression. Face-washing restores his composure for public presentation.</p>""",
    "32": """<p><strong>wayyāśîmû lô lĕḇaddô wĕlāhem lĕḇaddām wĕlammṣirîm hāʾōḵlîm ʾittô lĕḇaddām kî lōʾ yûḵlûn hammiṣrîm lĕʾĕḵōl ʾet-hāʿiḇrîm leḥem kî-tôʿēḇāh hîʾ lĕmiṣrāyim</strong> — "They served him by himself, and them by themselves, and the Egyptians who ate with him by themselves, because the Egyptians could not eat bread with the Hebrews, for that is an abomination (<em>tôʿēḇāh</em>) to Egypt." <em>Tôʿēḇāh</em> (H8441, abomination/detestable thing) — the same strong ritual-purity term used throughout Leviticus and Deuteronomy for Israel's covenant prohibitions (Deut 7:25-26; Lev 18:22). Here it appears from the Egyptian side: sharing a table with Hebrews is an abomination to Egyptians. The narrator presents this without condemnation — it is a simple cultural-religious fact that shapes the logistics. The three-table arrangement (Joseph, Egyptians, Hebrews) captures the social stratification: Joseph alone at the apex, the Egyptians separate, the brothers separate.</p>""",
    "33": """<p><strong>wayyēšĕḇû lĕpānāyw habĕḵōr kĕḇeḵōrātô wĕhaṣṣāʿîr kiṣĕʿîrātô wayyitĕmĕhû hāʾănāšîm ʾîš ʾel-rēʿēhû</strong> — "They were seated before him — the firstborn according to his birthright, and the youngest according to his youth — and the men looked at one another in amazement (<em>wayyitĕmĕhû</em>)." <em>Wayyitĕmĕhû</em> (Hithpael of <em>tāmah</em>, H8539, to be astonished/stupefied) — the brothers are speechless with amazement. The seating by birth-order — when they have never told Joseph their ages — is an inexplicable miracle to them. It is the first crack in the naturalistic explanation of events: something beyond coincidence is ordering their affairs. The birth-order seating also directly reverses the birth-order violation that started the family's crisis: Jacob's favoring of Joseph over older brothers.</p>""",
    "34": """<p><strong>wayyiśśāʾ mǎśʾōt mēʾittô ʾălêhem waṯṯēreḇ maśʾat binyāmîn mimmǎśʾōt kullām ḥāmēš yāḏôt</strong> — "Portions were sent to them from his table, and Benjamin's portion was five times as much as anyone else's." <em>Ḥāmēš yāḏôt</em> (five hands/portions) — the number five is the royal Egyptian number throughout the Joseph cycle: five changes of garments for Benjamin (45:22), five years of famine remaining (45:6), one-fifth taken during the seven good years (41:34). The "five portions" for Benjamin parallel the five-fold honor — Benjamin receives royal-scale provision before the brothers know his provider. The measure of provision is the measure of love Joseph cannot yet openly express.</p>"""
  },
  "44": {
    "1": """<p><strong>wayyĕṣaw ʾet-ʾăšer ʿal-bêtô lēʾmōr mallēʾ ʾet-ʾamtĕḥōt hāʾănāšîm ʾōḵel kaʾăšer yûḵlûn śēʾt</strong> — "Joseph commanded his household steward, 'Fill the men's sacks with food, as much as they can carry.'" The command is private, to the steward — the brothers have no knowledge of what is being arranged against them. The verb <em>mallēʾ</em> (fill, Piel of <em>mālaʾ</em>, H4390) — generous filling; Joseph is not setting a trap out of cruelty but designing an encounter that will bring the moral reckoning that the narrative requires for complete reconciliation.</p>""",
    "2": """<p><strong>wĕʾet-gaḇîʿî gaḇîaʿ hakkesep śîm bĕpî ʾamtaḥat haqqāṭān wĕʾēt kesef šiḇrô</strong> — "And put my cup — the silver cup — in the mouth of the youngest one's sack." <em>Gaḇîaʿ</em> (H1375, cup/goblet) — used only in this chapter (vv2,12,16,17) and in Jer 35:5. The term denotes a specific type of wide-mouthed drinking cup, distinct from <em>kôs</em> (the cupbearer's serving cup in ch40). The specificity "my cup, the silver cup" — the double-identification signals its value and personal significance; this is not just any cup but Joseph's personal vessel. Silver cups were among the most precious domestic objects in the ancient world.</p>""",
    "3": """<p><strong>habbōqer ʾôr wĕhāʾănāšîm šullĕḥû hēmmāh waḥămōrêhem</strong> — "At daybreak the men were sent off with their donkeys." <em>Šullĕḥû</em> (Pual of <em>šālaḥ</em>, H7971, to be sent away) — the passive: "they were sent away." The sending-verb that governs the Joseph narrative: in 45:5,7,8 Joseph will declare God sent him (<em>šĕlāḥanî ʾĕlōhîm</em>). Here the brothers are sent away — only to be brought back. The morning departure is routine; the overtaking will be the rupture.</p>""",
    "4": """<p><strong>hēm yāṣĕʾû ʾet-hāʿîr lōʾ hirḥîqû wĕyôsēp ʾāmar laʾăšer ʿal-bêtô qûm rĕḏōp ʾaḥărê hāʾănāšîm</strong> — "They had not gone far from the city when Joseph said to his steward, 'Pursue the men at once.'" The narrative compression — they had barely left, and Joseph immediately dispatches pursuit — creates tension. The steward becomes the instrument of accusation, not Joseph himself; this preserves Joseph's ability to receive them back in the house and eventually unmask himself privately (45:1).</p>""",
    "5": """<p><strong>hălôʾ zeh ʾăšer yište ʾăḏōnî bô wĕhûʾ naḥēš yĕnaḥēš bô</strong> — "Is this not the cup my lord drinks from and uses for divination (<em>naḥēš yĕnaḥēš</em>)?" <em>Naḥēš yĕnaḥēš</em> (Piel infinitive absolute + imperfect of <em>nāḥaš</em>, H5172, to practice divination/augury) — the emphatic construction: "he divines with divining." Egyptian hydromancy — reading omens from liquid poured into a silver or bronze cup — was a documented practice. Whether Joseph actually practiced this is ambiguous; the steward may be embellishing the accusation for effect. Genesis never presents Joseph as a diviner by practice; his interpretations are consistently attributed to God (40:8; 41:16). The claim functions as legal intensification: the stolen item is not just valuable but sacred.</p>""",
    "6": """<p><strong>wayyassiguhem wayyĕḏabbēr ʾălêhem ʾet-haddĕḇārîm hāʾēlleh</strong> — "He overtook them and spoke these words to them." <em>Wayyassiguhem</em> (Hiphil of <em>nāśag</em>, H5381, to overtake/catch up) — the pursuit-catch verb; the same word used for Laban overtaking Jacob (31:23,25). The overtaking is swift; the accusation immediately follows without opportunity for defense.</p>""",
    "7": """<p><strong>wayyōʾmĕrû ʾēlāyw lāmmāh yĕḏabbēr ʾăḏōnî kaddĕḇārîm hāʾēlleh ḥālîlāh laʿăḇāḏeḵā mēʿăśôṯ kaddāḇār hazzeh</strong> — "They said to him, 'Why does my lord speak such words as these? Far be it (<em>ḥālîlāh</em>) from your servants to do such a thing!'" <em>Ḥālîlāh</em> (H2486, far be it / God forbid / it is a desecration) — the strongest oath-formula in biblical Hebrew, invoking the idea that the suggested act would be a <em>ḥālāl</em> (a desecration, a profaning of something sacred). Used by Abraham ("Far be it from you to do such a thing!" Gen 18:25), by Joseph himself (44:17), by David ("Far be it from me, YHWH!" 1 Sam 26:11). The brothers' protest is forceful — this is not a mild denial but an oath-formula.</p>""",
    "8": """<p><strong>hēn kesef ʾăšer māṣāʾnû bĕpî ʾamtĕḥōtênû hăšîḇōnû ʾēleḵā mēʾereṣ kĕnaʿan wĕʾêḵāh ninōb mibêt ʾăḏōneḵā kesef ʾô zāhāḇ</strong> — "We even returned to you the silver we found in our sacks; how then could we steal silver or gold from your master's house?" The argument is logical: men who returned found silver voluntarily would not steal from the master's own house. The brothers use the evidence of their own honesty (the returned silver of ch42) as the exculpatory argument. Ironically, the returned silver was itself Joseph's arrangement — he is now using their honesty to test them further.</p>""",
    "9": """<p><strong>ʾăšer yimmāṣēʾ ʾittô mēʿăḇāḏeḵā wāmēt wĕgam-ʾănaḥnû nihyeh laʾăḏōnî laʿăḇāḏîm</strong> — "Whichever of your servants has it shall die, and the rest of us will become my lord's slaves." The self-condemning offer is legally reckless — they are so confident of their innocence that they offer the maximum penalty. The word <em>wāmēt</em> (and he shall die) echoes the earlier "we will surely die" if they go to Egypt without Benjamin (42:20). The brothers have moved from fearing death to offering it as proof of innocence. When the cup is found in Benjamin's sack, this oath will hang over them.</p>""",
    "10": """<p><strong>wayyōʾmer gam-ʿattāh ḵiḏḇārêḵem kēn-hûʾ ʾăšer yimmāṣēʾ ʾittô yihyeh-llî ʿāḇeḏ wĕʾattem tihyû nĕqiyyîm</strong> — "He said, 'Very well; let it be as you say — whoever is found with it will be my slave, but the rest of you will be free from blame.'" <em>Nĕqiyyîm</em> (H5355, innocent/free from guilt) — the steward modifies the brothers' oath: instead of death + slavery for all, only the offender becomes a slave; the rest go free. This modification is crucial: it creates the scenario in ch45 where Judah must choose between keeping his pledge to his father (bring Benjamin back) and the steward's offer (go home free). The test is designed to reveal whether the brothers will again abandon a son of Rachel to save themselves.</p>""",
    "11": """<p><strong>wayyĕmahărû wayyôrîdû ʾîš ʾet-ʾamtaḥtô ʾarṣāh wayyipĕtĕḥû ʾîš ʾamtaḥtô</strong> — "Each man quickly lowered his sack and opened it." <em>Wayyĕmahărû</em> (Piel of <em>māhar</em>, H4116, to hurry) — the urgency of the confident: they hurry to prove their innocence. The speed of compliance contrasts with what is about to happen; their hurry only accelerates their devastation.</p>""",
    "12": """<p><strong>wayyĕḥappēś baggāḏôl hēḥēl ûḇaqqāṭōn killāh wayyimmāṣēʾ haggāḇîaʿ bĕʾamtaḥat binyāmîn</strong> — "He searched, beginning with the oldest and finishing with the youngest; the cup was found in Benjamin's sack." The search begins with the eldest — adding suspense by confirming each brother's innocence one by one — and ends with Benjamin. The word <em>wayyimmāṣēʾ</em> (and it was found, Niphal of <em>māṣāʾ</em>, H4672) — the passive "was found"; this is the same verb used for Joseph's cup being "found" and for Judah's confession that "God has found out our guilt" (44:16). The finding-verb carries weight throughout the chapter.</p>""",
    "13": """<p><strong>wayyiqrĕʾû śimlōtām wayyaʿămas ʾîš ʿal-ḥămōrô wayyāšûḇû hāʿîrāh</strong> — "They tore their garments (<em>wayyiqrĕʾû śimlōtām</em>), each loaded his donkey, and returned to the city." <em>Qāraʿ śĕmālāh</em> (to tear a garment, H7167 + H8071) — the formal mourning-gesture for catastrophic loss or profound grief; Jacob tore his garments when he believed Joseph was dead (37:34). The brothers' tearing of garments signals that they experience this as a death — the death of their return, of Benjamin's freedom, of their father's remaining hope. They all return — not just Benjamin — which is the first evidence that the brothers have changed.</p>""",
    "14": """<p><strong>wayyāḇōʾ yĕhûḏāh wĕʾeḥāyw bêtāh yôsēp wĕhûʾ ʿôḏennû šām wayyippĕlû lĕpānāyw ʾarṣāh</strong> — "Judah and his brothers came to Joseph's house; Joseph was still there. They fell to the ground before him." <em>Wayyippĕlû lĕpānāyw ʾarṣāh</em> (they fell before him to the ground) — a prostration more abject than the earlier bowing: <em>nāpal</em> (H5307, to fall) rather than <em>hishtaḥăwāh</em> (to bow/prostrate). The complete fulfillment of Joseph's second dream (37:9-10: "the sun and moon and eleven stars bowed to me") — all eleven brothers prostrate before him. Judah is named first as the spokesman who will carry the brothers' fate.</p>""",
    "15": """<p><strong>wayyōʾmer lāhem yôsēp māh-hammǎʿăśeh hazzeh ʾăšer ʿăśîtem hălôʾ yĕḏaʿtem kî-naḥēš yĕnaḥēš ʾîš ʾăšer kāmōnî</strong> — "Joseph said to them, 'What is this deed that you have done? Do you not know that a man like me can divine?'" <em>Naḥēš yĕnaḥēš</em> (Piel infinitive absolute + imperfect) again — the emphasis on Joseph's supposed divinatory power. The question is rhetorical; Joseph knows exactly what happened. His claim to special knowledge sets up the brothers' theological interpretation in v16: "God has found out our guilt." They take the accusation as divine disclosure.</p>""",
    "16": """<p><strong>wayyōʾmer yĕhûḏāh mah-nōmar laʾăḏōnî mah-nĕḏabbēr ûmah-niṣṭaddāq hāʾĕlōhîm māṣāʾ ʾet-ʿăwōn ʿăḇāḏeḵā</strong> — "Judah said, 'What can we say to my lord? What can we speak? How can we justify ourselves (<em>niṣṭaddāq</em>)? God has found out the guilt of your servants.'" Three rhetorical questions in sequence — <em>mah-nōmar… mah-nĕḏabbēr… ûmah-niṣṭaddāq</em> — produce a speechless conclusion: there is nothing to say, nothing to speak, no self-justification possible. <em>Niṣṭaddāq</em> (Hithpael of <em>ṣāḏaq</em>, H6663, to justify oneself) — echoes Tamar's vindication in 38:26 (<em>ṣāḏĕqāh mimmennî</em>). <em>Hāʾĕlōhîm māṣāʾ ʾet-ʿăwōn</em> (God has found out the guilt) — Judah interprets the cup-finding as divine disclosure of their real guilt — the selling of Joseph. They are not confessing to the cup-theft (they didn't do it) but to the unresolved, unconfessed evil of ch37. God's providence has brought them to the moment of reckoning.</p>""",
    "17": """<p><strong>wayyōʾmer ḥālîlāh llî mēʿăśôṯ zōʾt hāʾîš ʾăšer nimmāṣāʾ haggāḇîaʿ bĕyāḏô hûʾ yihyeh-llî ʿāḇeḏ wĕʾattem ʿălû lĕšālôm ʾel-ʾăḇîḵem</strong> — "He said, 'Far be it (<em>ḥālîlāh</em>) from me to do such a thing! Only the man in whose hand the cup was found shall be my slave; as for you, go up in peace to your father.'" Joseph uses the <em>ḥālîlāh</em> oath-formula himself — matching the brothers' oath of v7. His offer is the same as the steward's (v10): only the offender stays, the rest go free. This is the pivot point of the test: will the brothers walk away from Benjamin as they walked away from Joseph?</p>""",
    "18": """<p><strong>wayyiggaš ʾēlāyw yĕhûḏāh wayyōʾmer bî ʾăḏōnî yĕḏabbēr-nāʾ ʿaḇdĕḵā ḏāḇār bĕʾoznê ʾăḏōnî wĕʾal-yiḥar ʾappĕḵā bĕʿaḇdĕḵā</strong> — "Then Judah came near (<em>wayyiggaš</em>) to him and said, 'Please, my lord, let your servant speak a word in my lord's ears, and let not your anger burn against your servant.'" <em>Wayyiggaš</em> (Niphal of <em>nāgaš</em>, H5066, to draw near/approach) — the approach of the intercessor. This verb is used for the approach of prayer, petition, and covenant negotiation: Abraham's drawing near to plead for Sodom (18:23: <em>wayyiggaš ʾaḇrāhām</em>), Moses drawing near to speak with God (Exod 24:2). Judah's approach to Joseph mirrors Abraham's approach to YHWH — a mortal approaching ultimate authority to plead for others. The plea that follows (vv18-34) is the most sustained piece of rhetoric in Genesis.</p>""",
    "19": """<p><strong>ʾăḏōnî šāʾal ʾet-ʿăḇāḏāyw lēʾmōr ha-yēš lāḵem ʾāḇ ʾô-ʾāḥ</strong> — "My lord asked his servants, saying, 'Have you a father or a brother?'" Judah begins his speech with a recounting of events — the classic structure of a legal defense: state the facts chronologically. By beginning with Joseph's own question, Judah establishes that the family details were disclosed in response to interrogation, not volunteered. The speech covers five sections: (1) the disclosure of Benjamin's existence (vv19-21); (2) Joseph's demand for Benjamin (vv22-23); (3) Jacob's resistance (vv24-29); (4) the stakes — Jacob's life (vv30-31); (5) Judah's substitution offer (vv32-34).</p>""",
    "20": """<p><strong>wayyōmer yēš-lānû ʾāḇ zāqēn wĕyeled zĕqunîm qāṭān wĕʾāḥîw mēt wayyiwwāṯer hûʾ lĕḇaddô lĕʾimmô wĕʾāḇîw ʾăhēḇô</strong> — "We said to my lord, 'We have an aged father, and a young child of his old age; his brother is dead, and he alone is left of his mother, and his father loves him.'" <em>Zĕqunîm</em> (old age's child, H2207 — child born to an old man, with the emotional investment that implies) — same term for Joseph in 37:3: "<em>ben-zĕqunîm</em>." Benjamin occupies the same position Joseph had — the beloved son of Jacob's old age, the surviving son of Rachel. Judah's recounting for Joseph that "his brother is dead" — telling Joseph that he himself is "dead" — is the narrative's deepest irony. <em>Lĕḇaddô</em> (alone, H905) — the solitude of Jacob without Benjamin echoes Jacob's solitude after Joseph's "death."</p>""",
    "21": """<p><strong>waṯṯōʾmer ʾel-ʿăḇāḏeḵā hôrîḏuhû ʾēlay wĕʾāśîmāh ʿênî ʿālāyw</strong> — "You said to your servants, 'Bring him down to me, so I may set my eyes on him.'" <em>Wĕʾāśîmāh ʿênî ʿālāyw</em> (I will set my eye on him) — the idiom for special personal attention and protective oversight. Judah quotes Joseph's own words back to him: Joseph's protective gaze toward Benjamin is now the basis of the plea. The "setting of eyes" is also the verb of special attention used for divine oversight of the land of Canaan (Deut 11:12: "YHWH's eyes are always on it").</p>""",
    "22": """<p><strong>wayyōʾmer ʾel-ʿăḇāḏeḵā lōʾ-yûḵal hannáʿar laʿăzōḇ ʾet-ʾāḇîw wĕʿāzaḇ ʾet-ʾāḇîw wāmēt</strong> — "We said to my lord, 'The boy cannot leave his father; if he were to leave his father, his father would die.'" The causal chain is explicitly stated: Benjamin's absence → father's death. This is not rhetorical embellishment — Jacob had already nearly been destroyed by Joseph's "death" (37:35: "he refused to be comforted"). Judah is explaining a clinical family fact. The word <em>wāmēt</em> (and he would die) — death as the consequence of separation, echoing the life/death polarity of the whole narrative.</p>""",
    "23": """<p><strong>waṯṯōʾmer ʾel-ʿăḇāḏeḵā ʾim-lōʾ yērēḏ ʾăḥîḵem haqqāṭōn ʾittĕḵem lōʾ tōsipûn lirʾôt pānāy</strong> — "You said to your servants, 'If your youngest brother does not come down with you, you will not see my face again.'" Judah quotes Joseph's ultimatum back to him — not as accusation but as explanation of the bind they are in. The phrase <em>lirʾôt pānāy</em> (to see my face) echoes the original warning in 43:3 (<em>hēʿēḏ hēʿîḏ ḇānû hāʾîš</em>: "the man solemnly warned us"). Judah is showing Joseph that every step they took was in response to Joseph's own commands.</p>""",
    "24": """<p><strong>wayhî kî ʿālînû ʾel-ʿaḇdĕḵā ʾāḇî wannaggēd-lô ʾēt diḇrê ʾăḏōnî</strong> — "When we went up to your servant my father, we told him what my lord had said." The report to Jacob is faithful: the brothers transmitted Joseph's conditions accurately. Judah's repetition of the events is establishing their honesty throughout — they have been obedient to the official's commands at every step.</p>""",
    "25": """<p><strong>wayyōʾmer ʾāḇînû šûḇû šiḇrû-lānû mĕʿaṭ-ʾōḵel</strong> — "Our father said, 'Go back and buy a little food.'" Jacob's minimizing language — <em>mĕʿaṭ</em> (a little) — reflects his reluctance even in need; he cannot bring himself to send Benjamin and tries to limit the exposure by limiting the trip.</p>""",
    "26": """<p><strong>wayyōʾmer lōʾ nûḵal lārēḏet ʾim-yeš-ʾāḥînû haqqāṭōn ʾittānû wĕyāraḏnû</strong> — "We said, 'We cannot go down; only if our youngest brother is with us will we go down.'" The brothers' condition is absolute: no Benjamin, no Egypt. This resolves Jacob's wavering with a hard constraint.</p>""",
    "27": """<p><strong>wayyōʾmer ʿaḇdĕḵā ʾāḇî ʾēlênû ʾattem yĕḏaʿtem kî šĕnayim yālĕḏāh-llî ʾišti</strong> — "Your servant my father said to us, 'You know that my wife bore me two sons.'" Judah quotes Jacob's speech — and Jacob's words are devastating in their dramatic irony: "my wife" — Rachel, the beloved wife — "bore me two sons." Jacob has two surviving sons of Rachel: Joseph (who he believes is dead) and Benjamin. Joseph is hearing his own father speak of his death through Judah's mouth.</p>""",
    "28": """<p><strong>wayyēṣēʾ hāʾeḥāḏ mēʾittî wāʾōmar ʾak ṭārōp ṭōrap wayyĕhî-llô-rōph ʿaḏ-hēnnāh</strong> — "The one went out from me, and I said, 'Surely he has been torn apart (<em>ṭārōp ṭōrap</em>)'; and I have not seen him since." <em>Ṭārōp ṭōrap</em> (Qal infinitive absolute + perfect of <em>ṭārap</em>, H2963, to tear/rend — as a wild animal tears prey) — the same construction the brothers used when they deceived Jacob with Joseph's coat: "this we found — <em>hakkēr-nāʾ</em> — is it your son's?" and Jacob concluded "a wild animal has torn him" (37:33: <em>ṭārōp ṭōrap yôsēp</em>). Judah is quoting Jacob quoting the brothers' lie back to Joseph — the innocent man hears his own murder being described by the man who served as its architect. The dramatic irony is almost unbearable.</p>""",
    "29": """<p><strong>ûlĕqaḥtem gam-ʾet-zeh mēʿim pānay wĕqārāhû ʾāsôn wĕhôraḏtem ʾet-śêḇātî bĕrāʿāh šĕʾōlāh</strong> — "If you take this one from me also and harm comes to him, you will bring my gray hairs down to Sheol in grief." <em>Śêḇāh</em> (H7872, gray hair/old age — the physical sign of accumulated years) + <em>šĕʾōl</em> (H7585, the underworld/grave/place of the dead) — "you will bring my gray hair to Sheol." Jacob's life is at stake in Benjamin's safety. This is not mere rhetoric; Judah is conveying his father's literal condition. The phrase completes the arc of Jacob's suffering: the gray-haired patriarch who has already lost one beloved son cannot survive losing the other.</p>""",
    "30": """<p><strong>wĕʿattāh kĕḇōʾî ʾel-ʿaḇdĕḵā ʾāḇî wĕhannáʿar ʾênennu ʾittānû wĕnapšô qĕšûrāh ḇĕnapšô</strong> — "Now if I come to your servant my father and the boy is not with us — since his life (<em>napšô</em>) is bound up in the boy's life (<em>bĕnapšô</em>) —" <em>Napšô qĕšûrāh ḇĕnapšô</em> (his life is bound up in his life) — <em>nāpāš</em> (H5315, soul/life/self/person) twice, with <em>qāšar</em> (H7194, to bind/tie together) between them. The binding-together of two souls is the most intimate form of covenant-love in biblical Hebrew: Jonathan's soul "bound" to David's soul (1 Sam 18:1: <em>nĕpešô niqšĕrāh bĕnepěš dāwîḏ</em>). Jacob's soul is bound to Benjamin's as covenant-love binds two persons. If Benjamin dies, Jacob's soul tears free — which is death.</p>""",
    "31": """<p><strong>wĕhāyāh kirʾōtô kî-ʾên hannáʿar wāmēt</strong> — "When he sees that the boy is not with us, he will die." The stark prediction — four Hebrew words — is Judah's climactic statement of the stakes. No rhetorical elaboration; just the blunt fact: no Benjamin → father dies. This is the weight against which Judah will offer himself.</p>""",
    "32": """<p><strong>kî ʿaḇdĕḵā ʿāraḇ ʾet-hannáʿar mēʿim ʾāḇî lēʾmōr ʾim-lōʾ ʾăḇîʾennû ʾēleḵā wĕḥāṭāʾtî lĕʾāḇî kāl-hayyāmîm</strong> — "For your servant became surety (<em>ʿāraḇ</em>) for the boy to my father, saying, 'If I do not bring him back to you, I will bear the blame before my father all my days.'" <em>ʿĀraḇ</em> (H6148, to become surety/pledge, Qal perfect) — Judah's surety-pledge from 43:9 is now his binding obligation. The same root as <em>ʿēreḇôn</em> (pledge, ch38) — but there it was a careless pledge; here it is a life-pledge. Judah's transformation is complete: the man who sold Joseph for twenty pieces of silver now pledges his own life for Benjamin.</p>""",
    "33": """<p><strong>wĕʿattāh yēšeḇ-nāʾ ʿaḇdĕḵā taḥat hannáʿar ʿeḇeḏ laʾăḏōnî wĕhannáʿar yaʿal ʿim-ʾeḥāyw</strong> — "Now let your servant remain instead of (<em>taḥat</em>) the boy as a slave to my lord, and let the boy go up with his brothers." <em>Taḥat</em> (H8478, under/in place of/instead of) — the substitution preposition. This is the same word used for Abraham's ram offered in Isaac's place: <em>wayyaʿălēhû lĕʿōlāh taḥat bĕnô</em> (he offered it as a burnt offering in place of his son, 22:13). Judah's voluntary substitution — "I instead of the boy" — is structurally identical to the ram's substitution for Isaac. The man who failed to substitute himself for Joseph in 37:26-27 (suggesting instead they sell him) now offers himself as a substitutionary slave. The moral reversal is complete and the echo to the Akedah is intentional.</p>""",
    "34": """<p><strong>kî-ʾêḵāh ʾeʿĕleh ʾel-ʾāḇî wĕhannáʿar ʾênennu ʾittî pen ʾerʾeh bārāʿ ʾăšer yimṣāʾ ʾet-ʾāḇî</strong> — "For how can I go back to my father if the boy is not with me? I am afraid of the evil that would come upon my father." <em>ʾêḵāh ʾeʿĕleh</em> (how can I go up?) — the rhetorical question as final argument. <em>Bārāʿ ʾăšer yimṣāʾ ʾet-ʾāḇî</em> (the evil/harm that would find my father) — <em>māṣāʾ</em> (to find/befall) used for evil overtaking someone; the same verb that found the cup (v12) and that God used to find their guilt (v16). Judah's speech ends not with self-justification but with his father's welfare. He has moved entirely outside himself.</p>"""
  },
  "45": {
    "1": """<p><strong>wĕlōʾ-yāḵōl yôsēp lĕhiṯʾappēq lĕḵōl hannĭṣṣāḇîm ʿālāyw wayyiqrāʾ hôṣîʾû kāl-ʾîš mēʿālay wĕlōʾ-ʿāmaḏ ʾîš ʾittô bĕhiṯwaddeaʿ yôsēp ʾel-ʾeḥāyw</strong> — "Joseph could no longer control himself (<em>lĕhiṯʾappēq</em>) before all who stood before him, and he cried, 'Remove every man from me!'" <em>Lĕhiṯʾappēq</em> (Hithpael infinitive of <em>ʾāpaq</em>, H662, to restrain/control oneself) — the Hithpael reflexive for the effort of self-containment. In 43:31 Joseph controlled himself (<em>wayyiṯʾappaq</em>); now the same verb's negation: he could no longer do it. Judah's substitution speech (44:18-34) broke through his restraint. The clearing of all attendants is deliberate — Joseph will reveal himself in private so the brothers are not shamed before Egyptians (cf. 45:1 <em>wĕhiṯwaddeaʿ yôsēp ʾel-ʾeḥāyw</em>, "as Joseph made himself known to his brothers"). The Hithpael of <em>yāḏaʿ</em> — "he made himself known" — the reflexive of the knowing-verb; an act of self-disclosure.</p>""",
    "2": """<p><strong>wayyittēn ʾet-qōlô bĕḇeḵî wayyišmĕʿû miṣrāyim wayyišmaʿ bêt parʿōh</strong> — "He wept aloud (<em>wayyittēn ʾet-qōlô bĕḇeḵî</em>) so that the Egyptians heard him and Pharaoh's household heard about it." <em>Wayyittēn ʾet-qōlô</em> (he gave his voice — the Hebrew idiom for crying out loudly) — the same idiom for Rachel's weeping in Jer 31:15 (<em>qôl bĕrāmāh nišmaʿ</em>, a voice heard in Ramah). Joseph's weeping is uncontainable — heard through walls, reported to Pharaoh's household. After years of administrative distance and controlled emotion (42:24, 43:30-31), the dam has broken completely.</p>""",
    "3": """<p><strong>wayyōʾmer yôsēp ʾel-ʾeḥāyw ʾănî yôsēp ha-ʿôḏ ʾāḇî ḥay wĕlōʾ-yāḵĕlû ʾeḥāyw laʿănôt ʾōtô kî niḇhălû mippānāyw</strong> — "Joseph said to his brothers, 'I am Joseph (<em>ʾănî yôsēp</em>)! Is my father still alive?' But his brothers could not answer him, for they were terrified (<em>niḇhălû</em>) before him." <em>ʾĂnî yôsēp</em> — three Hebrew words; the shortest, most devastating self-disclosure in Genesis. Two words of identity, one question about his father — his first words after the reveal are for Jacob, not about the brothers' guilt. <em>Niḇhălû</em> (Niphal of <em>bāhal</em>, H926, to be terrified/dismayed) — they are not merely surprised but terror-struck; the man they sold stands before them as the second ruler of Egypt. <em>Mippānāyw</em> (before his face/presence) — the face that Joseph had hidden, the face that he said they would not see without Benjamin (43:3,5), is now the face of their brother.</p>""",
    "4": """<p><strong>wayyōʾmer yôsēp ʾel-ʾeḥāyw gĕšû-nāʾ ʾēlay wayyiggāšû wayyōʾmer ʾănî yôsēp ʾăḥîḵem ʾăšer-mĕḵartem ʾōtî miṣrāymāh</strong> — "Joseph said, 'Come close to me, please (<em>gĕšû-nāʾ</em>).' And they came close. He said, 'I am Joseph your brother, whom you sold into Egypt.'" <em>Gĕšû-nāʾ</em> (Qal imperative plural + <em>nāʾ</em> of <em>nāgaš</em>, H5066, draw near) — Joseph calls his brothers near before the reconciling word. The physical approach precedes the word of grace — he will not speak forgiveness from a distance but draws them into intimacy. The fuller identification — "whom you sold into Egypt" — names the act without accusation; it is stated as fact, not charge, in preparation for the theological reframing of v5-8.</p>""",
    "5": """<p><strong>wĕʿattāh ʾal-tēʿāṣĕḇû wĕʾal-yiḥar bĕʿênêḵem kî-mĕḵartem ʾōtî hēnnāh kî lĕmiḥyāh šĕlāḥanî ʾĕlōhîm lĕpānêḵem</strong> — "Now do not be grieved (<em>ʾal-tēʿāṣĕḇû</em>) or angry with yourselves for selling me here, because God sent me before you to preserve life (<em>lĕmiḥyāh</em>)." Two verbs of negative emotion released: <em>ʿāṣaḇ</em> (H6087, to grieve/hurt/pain) + <em>ḥārar</em> (H2734, to burn/be kindled — the same root as "his anger burned," the idiom for hot rage). Joseph explicitly releases the brothers from both grief and anger about the selling. <em>Lĕmiḥyāh</em> (to preserve life, H4241 — from <em>ḥāyāh</em>, H2421, to live) — the preservation-of-life purpose clause answers Judah's plea in 43:8 (<em>wĕniḥyeh wĕlōʾ nāmût</em>, that we may live and not die). The narrative's telos was always <em>miḥyāh</em> — life. <em>Šĕlāḥanî ʾĕlōhîm</em> (God sent me) — the first of three uses of this sending-formula (vv5,7,8); God is named as the agent of Joseph's transportation to Egypt.</p>""",
    "6": """<p><strong>kî-zeh šĕnāṯayim hārāʿāḇ bĕqereḇ hāʾāreṣ wĕʿôḏ ḥāmēš šānîm ʾăšer ʾên-ḥārîš wĕqāṣîr</strong> — "For two years the famine has been in the land, and there are still five years in which there will be neither plowing nor harvest." The two + five = seven years frames the timeline precisely as Pharaoh's dreams predicted (41:26-27). Joseph provides the calculation as evidence of the plan's divine origin: the famine's duration confirms the interpretation, which confirms the divine planning that brought Joseph to Egypt at exactly the right time.</p>""",
    "7": """<p><strong>wayyišlāḥēnî ʾĕlōhîm lĕpānêḵem lāśûm lāḵem šĕʾērît bāʾāreṣ ûlĕhaḥăyôt lāḵem liplyêṭāh gĕḏōlāh</strong> — "God sent me (<em>wayyišlāḥēnî ʾĕlōhîm</em>) before you to preserve for you a remnant (<em>šĕʾērît</em>) on earth, and to keep you alive as a great survivor band (<em>pĕlêṭāh gĕḏōlāh</em>)." <em>Šĕʾērît</em> (H7611, remnant — what is left after disaster) — the remnant-theology vocabulary that will become central in Isaiah, Jeremiah, and Micah: God preserves a <em>šĕʾērît</em> through judgment. <em>Pĕlêṭāh gĕḏōlāh</em> (a great deliverance/band of survivors, H6413) — the word for those who escape calamity; used for survivors of war, flood, and exile. Joseph's mission is explicitly articulated in the vocabulary of prophetic remnant-theology: he is the instrument of the covenant-line's preservation through catastrophe.</p>""",
    "8": """<p><strong>wĕʿattāh lōʾ-ʾattem šĕlāḥtem ʾōtî hēnnāh kî hāʾĕlōhîm wayyĕśîmēnî lĕʾāḇ lĕparʿōh ûlĕʾāḏôn lĕḵol-bêtô ûmōšēl bĕḵol-ʾereṣ miṣrāyim</strong> — "So then it was not you who sent me here, but God (<em>lōʾ-ʾattem šĕlāḥtem ʾōtî hēnnāh kî hāʾĕlōhîm</em>); and he made me a father (<em>ʾāḇ</em>) to Pharaoh, lord of all his house, and ruler over all the land of Egypt." The theological pivot: "not you… but God." The brothers did send Joseph; Joseph does not deny the human act. But the ultimate agent was divine. This is the mature biblical theology of concursive divine sovereignty: God works through human agency, including sinful human agency, without reducing either the reality of the human act or the sovereignty of the divine purpose (cf. Acts 2:23: "delivered up according to the definite plan and foreknowledge of God… you crucified and killed by the hands of lawless men"). Joseph's three titles — <em>ʾāḇ lĕparʿōh</em> (father/counselor to Pharaoh — a royal advisor title attested in Egyptian records), <em>ʾāḏôn lĕḵol-bêtô</em> (lord of all his house), <em>môšēl bĕḵol-ʾereṣ miṣrāyim</em> (ruler over all Egypt) — summarize the exaltation arc from 41:40-45.</p>""",
    "9": """<p><strong>mahărû wĕʿălû ʾel-ʾāḇî wĕʾămartem ʾēlāyw kōh ʾāmar bĕnĕḵā yôsēp</strong> — "Hurry and go up to my father and say to him, 'Thus says your son Joseph.'" The messenger-formula <em>kōh ʾāmar</em> (thus says) — the prophetic delivery formula; Joseph uses the royal-prophetic speech form to communicate to Jacob. The urgency (<em>mahărû</em> — Piel, hurry) mirrors the famine-urgency that has driven the narrative; now the urgency is joyful: haste to bring good news.</p>""",
    "10": """<p><strong>wĕyāšaḇtā bĕʾereṣ-gōšen wĕhāyîtā qārôḇ ʾēlay ʾattāh ûḇāneḵā ûḇnê ḇāneḵā wĕṣōʾnĕḵā ûḇĕqārĕḵā wĕḵol-ʾăšer-lāḵ</strong> — "You shall live in the land of Goshen and be near me — you and your children and your grandchildren, your flocks and your herds and all that you have." <em>Gōšen</em> (H1657, Goshen) — the fertile Nile delta region allocated to Israel; the name may derive from Egyptian or may be a Semitic place-name. The promise of proximity — <em>qārôḇ ʾēlay</em> (near to me) — is the relational gift at the center of the material provision. Joseph is not only providing food but restoring family presence after twenty-two years of separation.</p>""",
    "11": """<p><strong>wĕḵilkaltî ʾōtĕḵā šām kî-ʿôḏ ḥāmēš šānîm rāʿāḇ pen-tiwwārēš ʾattāh ûḇêtĕḵā wĕḵol-ʾăšer-lāḵ</strong> — "I will provide for you (<em>wĕḵilkaltî</em>) there, for there are still five years of famine, so that you and your household and all that you have do not fall into poverty." <em>Kûl</em> (H3557, Pilpel: to sustain/provide for/contain — to hold someone in provision) — Joseph will "contain" or "sustain" his father; the same verb is used for God providing manna (sustaining Israel in the wilderness) and for Solomon's administration providing for his household. The five remaining famine years create the urgency for immediate relocation.</p>""",
    "12": """<p><strong>wĕhinnēh ʿênêḵem rōʾôt wĕʿênê ʾăḥî binyāmîn kî-pî haMĕḏabbēr ʾălêḵem</strong> — "And behold, your eyes can see, and the eyes of my brother Benjamin, that it is my own mouth speaking to you." <em>Pî haMĕḏabbēr ʾălêḵem</em> (my mouth speaking to you) — an appeal to direct eyewitness testimony: their own eyes confirm they are seeing Joseph, their own ears confirm they are hearing him, not a proxy. The mention of Benjamin (<em>ʾăḥî ḇinyāmîn</em>) — "my brother Benjamin" — is the first time Joseph publicly identifies the kinship; Benjamin's eyes are named alongside theirs as co-witnesses.</p>""",
    "13": """<p><strong>wĕhiggadtem lĕʾāḇî ʾet-kāl-kĕḇôḏî bĕmiṣrāyim wĕʾēt kāl-ʾăšer rĕʾîtem ûmihhartem wĕhôraḏtem ʾet-ʾāḇî hēnnāh</strong> — "Tell my father about all my honor (<em>kĕḇôḏî</em>) in Egypt, and everything you have seen; and hurry and bring my father down here." <em>Kĕḇôḏî</em> (my glory/honor/weight, H3519, from <em>kāḇēḏ</em>) — the root that opened ch43 (<em>kāḇēḏ</em>, the heavy famine). The famine's heaviness and Joseph's honor/glory share the same root — the wordplay traces the arc from famine-heaviness to honor-weightiness. Joseph's glory in Egypt is the evidence that God's hand is in the events; this is what Jacob must be told.</p>""",
    "14": """<p><strong>wayyippōl ʿal-ṣawwĕʾrê ḇinyāmîn ʾāḥîw wayyēḇk ûḇinyāmîn bāḵāh ʿal-ṣawwĕʾrāyw</strong> — "He fell on his brother Benjamin's neck (<em>ʿal-ṣawwĕʾrê ḇinyāmîn</em>) and wept; and Benjamin wept on his neck." <em>Ṣawwāʾr</em> (H6677, neck/throat) — the neck-embrace formula — falling on another's neck — is the biblical idiom for the most intimate reunion embrace: Laban fell on Jacob's neck (29:13), Esau fell on Jacob's neck and wept (33:4). Joseph's embrace of Benjamin is the reunion of the two sons of Rachel — the only two who share both father and mother. The symmetry (<em>wayyēḇk… bāḵāh</em>) — both weeping, each on the other's neck — is reciprocal grief-and-joy embodied.</p>""",
    "15": """<p><strong>wayyĕnaššēq lĕḵol-ʾeḥāyw wayyēḇk ʿălêhem wĕʾaḥărê kēn dibbĕrû ʾeḥāyw ʾittô</strong> — "He kissed all his brothers and wept over them; afterward his brothers talked with him." <em>Wayyĕnaššēq lĕḵol-ʾeḥāyw</em> (he kissed all his brothers) — the kiss of full reconciliation; Joseph initiates the embrace with each brother. <em>Wĕʾaḥărê kēn dibbĕrû</em> (afterward his brothers spoke with him) — the brothers' silence during the revelation (v3: "they could not answer him") is broken only after the kisses and tears. Words are possible only after the physical reconciliation has occurred. The narrator's understatement — "they talked with him" — leaves the content of that conversation to the imagination.</p>""",
    "16": """<p><strong>wĕhaqōl nišmaʿ bêt parʿōh lēʾmōr bāʾû ʾăḥê yôsēp wayyîṭaḇ bĕʿênê parʿōh ûḇĕʿênê ʿăḇāḏāyw</strong> — "The news reached Pharaoh's house: 'Joseph's brothers have come.' It pleased Pharaoh and his servants." <em>Wayyîṭaḇ bĕʿênê parʿōh</em> (it was good in Pharaoh's eyes) — the standard approval formula. Pharaoh's generosity in vv17-20 is politically sensible (Joseph's family settling in Goshen strengthens his administration) and personally gracious. The Egyptian monarch's welcome of the Hebrew family is the beginning of Israel's sojourn in Egypt — which will become the context for the Exodus.</p>""",
    "17": """<p><strong>wayyōʾmer parʿōh ʾel-yôsēp ʾĕmōr ʾel-ʾaḥeḵā zōʾt ʿăśû ʿimĕsû ʾet-bĕʿîrĕḵem ûlĕḵû bōʾû ʾarṣāh kĕnaʿan</strong> — "Pharaoh said to Joseph, 'Tell your brothers, "Do this: load your animals and go back to the land of Canaan."'" Pharaoh takes over the invitation — making it royal command, not merely Joseph's personal wish. This elevates the summons: Jacob is invited not just by his son but by the most powerful ruler in the known world.</p>""",
    "18": """<p><strong>ûqĕḥû ʾet-ʾăḇîḵem wĕʾet-bêtêḵem ûḇōʾû ʾēlay wĕʾettĕnāh lāḵem ʾet-ṭûḇ ʾereṣ miṣrāyim wĕʾiḵlû ʾet-ḥēleḇ hāʾāreṣ</strong> — "Take your father and your households and come to me, and I will give you the best of the land of Egypt, and you shall eat the fat of the land." <em>Ṭûḇ ʾereṣ miṣrāyim</em> (the best of the land of Egypt) + <em>ḥēleḇ hāʾāreṣ</em> (the fat of the land) — two covenant-provision expressions. <em>Ḥēleḇ</em> (H2459, fat/richness/best portion) is the term for the choicest part of a sacrifice; "fat of the land" = its richest produce. Pharaoh is offering what God promised the patriarchs for Canaan — the reversal will be completed in the Exodus when Israel takes the land's <em>ḥēleḇ</em> back to Canaan.</p>""",
    "19": """<p><strong>wĕʾattāh ṣuwwêtāh zōʾt ʿăśû qĕḥû-lāḵem mēʾereṣ miṣrāyim ʿăgālôt lĕṭapĕḵem wĕlĕnĕšêḵem ûnĕśāʾtem ʾet-ʾăḇîḵem ûḇāʾtem</strong> — "And you are commanded: do this — take wagons from the land of Egypt for your little ones and your wives, and bring your father and come." <em>ʿĂgālôt</em> (H5699, wagons/carts — wheeled vehicles) — wagons were an Egyptian technological superiority; Canaan used pack animals. Pharaoh's provision of wagons is a sign of royal investment in the family's migration. The wagons will become the evidence Jacob needs (v27: "when he saw the wagons Joseph had sent").</p>""",
    "20": """<p><strong>wĕʿênĕḵem ʾal-tāḥōs ʿal-kĕlêḵem kî-ṭûḇ kol-ʾereṣ miṣrāyim lāḵem hûʾ</strong> — "Do not be concerned about your belongings, for the best of all the land of Egypt is yours." <em>Wĕʿênĕḵem ʾal-tāḥōs</em> (let not your eyes spare/regret) — literally "let your eyes not grieve over" leaving possessions behind. The royal instruction to travel light anticipates the Exodus command: Israel will leave Egypt but take the wealth of Egypt with them (Exod 12:36). Here the instruction runs the other direction — don't worry about what you leave behind in Canaan, for Egypt's best is yours.</p>""",
    "21": """<p><strong>wayyaʿăśû-ḵēn bĕnê yiśrāʾēl wayyittēn lāhem yôsēp ʿăgālôt ʿal-pî parʿōh wayyittēn lāhem ṣēḏāh laddāreḵ</strong> — "The sons of Israel did so; Joseph gave them wagons, according to Pharaoh's command, and he provided them with provisions for the journey." <em>ʿAl-pî parʿōh</em> (according to Pharaoh's mouth/command) — the royal authorization formula; Joseph executes the command but it is Pharaoh's authority that makes it binding and royal. The wagons and provisions are doubled in source: Joseph's love and Pharaoh's authority.</p>""",
    "22": """<p><strong>lĕḵullām nātan laʾîš ḥălipôt śĕmālôt ûlĕḇinyāmîn nātan šĕlōš mēʾôt kesef wĕḥāmēš ḥălipōt śĕmālôt</strong> — "To each he gave changes of clothes (<em>ḥălipôt śĕmālôt</em>); but to Benjamin he gave three hundred pieces of silver and five changes of garments." <em>Ḥălipôt śĕmālôt</em> (changes of garments/clothing) — clothing as the sign of status, identity, and honor throughout the Joseph narrative. Joseph's coat was taken from him (37:23); his garment became false evidence (39:12); he was clothed in linen at his elevation (41:42). Now he distributes garments to all his brothers — and five to Benjamin (the royal number, echoing the five portions of 43:34). The reversal is complete: the man stripped of his garment now clothes his family.</p>""",
    "23": """<p><strong>ûlĕʾāḇîw šālaḥ kĕzōʾt ʿăśārāh ḥămōrîm nōśĕʾîm miṭṭûḇ miṣrāyim wĕʿeśer ʾătōnōt nōśĕʾōt bār wāleḥem ûmāzôn lĕʾāḇîw laddāreḵ</strong> — "To his father he sent this: ten donkeys loaded with the good things of Egypt, and ten female donkeys loaded with grain, bread, and provisions for his father for the journey." The double ten (ten donkeys + ten female donkeys = twenty) — the twenty pieces of silver for which Joseph was sold (37:28) is echoed in the twenty donkeys of provision sent back. The goods of Egypt flowing to Jacob through Joseph reverse the direction of the transaction that sent Joseph to Egypt.</p>""",
    "24": """<p><strong>wayyĕšallaḥ ʾet-ʾeḥāyw wayyēlĕḵû wayyōʾmer ʾălêhem ʾal-tirgĕzû badāreḵ</strong> — "He sent his brothers off and they departed; he said to them, 'Do not quarrel on the way (<em>ʾal-tirgĕzû badāreḵ</em>).'" <em>Tirgĕzû</em> (Qal imperfect jussive of <em>rāgaz</em>, H7264, to tremble/quake/be disturbed/quarrel) — the word covers a semantic range from physical trembling (earth-quaking) to emotional agitation to interpersonal quarreling. Joseph's parting word is a preemptive peace-command: the guilt about what they did to him is now resolved, but the journey home is long and the brothers may still argue about blame. <em>Rāgaz</em> is used for God's agitation against enemies (Ps 99:1) and for the earth trembling at divine presence (Hab 3:7). Joseph uses the same word to warn against the interpersonal turbulence that guilt and recrimination produce.</p>""",
    "25": """<p><strong>wayyaʿălû mimmṣrāyim wayyāḇōʾû ʾereṣ kĕnaʿan ʾel-yaʿăqōḇ ʾăḇîhem</strong> — "They went up from Egypt and came to the land of Canaan, to their father Jacob." The ascending movement reverses the descents of the narrative: Joseph was brought down to Egypt (39:1), the brothers went down for grain (42:1-3), now they come back up (<em>wayyaʿălû</em>) to Canaan. The ascent signals the direction of covenant-return — up to the promised land.</p>""",
    "26": """<p><strong>wayyaggĕḏû lô lēʾmōr ʿôḏ yôsēp ḥay wĕkî-hûʾ mōšēl bĕḵol-ʾereṣ miṣrāyim wayyāpāg libbô kî lōʾ-hěʾĕmîn lāhem</strong> — "They told him, 'Joseph is still alive (<em>ʿôḏ yôsēp ḥay</em>)! He is ruler over all Egypt!' His heart became numb (<em>wayyāpāg libbô</em>), for he did not believe them." <em>Wayyāpāg libbô</em> (his heart became numb/faint, H6313 <em>pûg</em>, to grow numb/be faint/go cold) — this verb appears only here; it describes the physiological effect of overwhelming news on the heart. Jacob's heart cannot process what he is hearing; the organ that has been grieving for twenty-two years cannot immediately absorb the reversal. <em>Lōʾ-hěʾĕmîn lāhem</em> (he did not believe them) — the same root as <em>ʾĕmûnāh</em> (faithfulness) and <em>ʾāmēn</em>: Jacob's heart could not "amen" this news.</p>""",
    "27": """<p><strong>wayyĕḏabbĕrû ʾēlāyw ʾēt kāl-diḇrê yôsēp ʾăšer dibbēr ʾălêhem wayyarʾ ʾet-hāʿăgālôt ʾăšer-šālaḥ yôsēp lāśēʾt ʾōtô waṯṯĕḥî rûaḥ yaʿăqōḇ ʾăḇîhem</strong> — "When they told him all the words of Joseph that he had said to them, and when he saw the wagons that Joseph had sent to carry him, the spirit (<em>rûaḥ</em>) of their father Jacob revived (<em>waṯṯĕḥî</em>)." <em>Waṯṯĕḥî rûaḥ yaʿăqōḇ</em> (the spirit/breath of Jacob revived) — <em>ḥāyāh</em> (H2421, to live/come to life) applied to <em>rûaḥ</em> (H7307, spirit/breath/wind). The same verb used throughout this chapter for life-preservation (<em>lĕmiḥyāh</em>, vv5,7): Jacob's spirit comes alive again — the verb of life that Joseph was sent to effect (v5) now effects itself in his father. The wagons — <em>hāʿăgālôt</em> — are the material evidence; the living-spirit is the theological reality. Jacob sees the wagons and his dead spirit revives.</p>""",
    "28": """<p><strong>wayyōʾmer yiśrāʾēl raḇ ʿôḏ-yôsēp bĕnî ḥay ʾēlĕḵāh wĕʾerʾennû bĕṭerem ʾāmût</strong> — "Israel said, 'Enough! (<em>raḇ</em>) My son Joseph is still alive! I will go and see him before I die.'" <em>Raḇ</em> (H7227, much/many/enough/great) — used here as an exclamation of sufficiency: "Enough! — it is too much! — what more do I need?" The same word used for the "great multitude" and the "many" throughout the OT; here it explodes with emotional release. The narrator uses <em>yiśrāʾēl</em> (Israel, the covenant name) rather than <em>yaʿăqōḇ</em> (Jacob, the personal name) for this declaration — it is Israel-the-patriarch who speaks, not Jacob-the-grieving-father. <em>Bĕṭerem ʾāmût</em> (before I die) — the dying-before clause that has haunted the narrative (44:22,29,31); now reframed as urgency for life-giving reunion rather than grief. Jacob's last recorded words in ch45 are about seeing and living.</p>"""
  }
}

def main():
    existing = load_comm('mkt-original', 'genesis')
    before_count = sum(len(v) for v in existing.values())
    merge_comm(existing, GENESIS_ORIGINAL)
    save_comm('mkt-original', 'genesis', existing)

    result = load_comm('mkt-original', 'genesis')
    after_count = sum(len(v) for v in result.values())
    print(f'  Verses added: {after_count - before_count}')
    for ch in [43, 44, 45]:
        ck = str(ch)
        n = len(result.get(ck, {}))
        print(f'  Ch {ch}: {n} verses present')
    total_chs = len(result)
    total_vv = sum(len(v) for v in result.values())
    print(f'  Genesis total: {total_chs} chapters, {total_vv} verses with original data')
    print('Genesis 43-45 mkt-original written.')

if __name__ == '__main__':
    main()
